parameters.jsCode:
const postData = $input.first().json;
const webhookData = $('Webhook: Receive Approval').first().json.body;

if (webhookData.scheduled_at) {
  return [{ json: { ...postData[0], scheduled_at: webhookData.scheduled_at } }];
}

const istOffset = 5.5 * 60 * 60 * 1000;
const nowIST = new Date(Date.now() + istOffset);
const h = nowIST.getUTCHours(), day = nowIST.getUTCDay();
const isWeekday = day >= 1 && day <= 5;
let target = new Date(nowIST);

if (isWeekday && h < 8)       target.setUTCHours(8, 0, 0, 0);
else if (isWeekday && h < 18) target.setUTCHours(18, 0, 0, 0);
else {
  target.setUTCDate(target.getUTCDate() + 1);
  while ([0,6].includes(target.getUTCDay())) target.setUTCDate(target.getUTCDate() + 1);
  target.setUTCHours(8, 0, 0, 0);
}

const scheduledUTC = new Date(target.getTime() - istOffset);
console.log(`Scheduled: ${target.toISOString()} IST`);

return [{
  json: {
    post_id:              postData[0]?.id || webhookData.post_id,
    idea_title:           postData[0]?.idea_title || '',
    linkedin_draft:       postData[0]?.linkedin_draft || '',
    instagram_draft:      postData[0]?.instagram_draft || '',
    carousel_slides:      postData[0]?.carousel_slides || [],
    carousel_image_urls:  postData[0]?.carousel_image_urls || [],
    youtube_script:       postData[0]?.youtube_script || '',
    youtube_video_url:    postData[0]?.youtube_video_url || webhookData.youtube_video_url || '',
    image_url:            postData[0]?.image_url || '',
    scheduled_at:         scheduledUTC.toISOString()
  }
}];

