const items = $input.all();
const scheduled = $('Code: Calculate Optimal Schedule Time').first().json;

// LinkedIn
const liData = items.find(i => i.json.likesSummary || i.json.totalSocialActivityCounts) || {};
const liLikes = liData.json?.likesSummary?.totalLikes || liData.json?.totalSocialActivityCounts?.numLikes || 0;
const liComments = liData.json?.commentsSummary?.totalFirstLevelComments || 0;
const liShares = liData.json?.totalSocialActivityCounts?.numShares || 0;
const liImpressions = liData.json?.totalShareStatistics?.impressionCount || liLikes * 50;

// Instagram
const igRaw = items.find(i => i.json.data && Array.isArray(i.json.data));
const igMetrics = {};
(igRaw?.json?.data || []).forEach(m => { igMetrics[m.name] = m.values?.[0]?.value || 0; });
const igLikes = igMetrics.likes || 0, igComments = igMetrics.comments || 0;
const igReach = igMetrics.reach || 0, igSaves = igMetrics.saved || 0;

// YouTube
const ytRaw = items.find(i => i.json.items && Array.isArray(i.json.items));
const ytStats = ytRaw?.json?.items?.[0]?.statistics || {};
const ytViews = parseInt(ytStats.viewCount || '0');
const ytLikes = parseInt(ytStats.likeCount || '0');
const ytComments = parseInt(ytStats.commentCount || '0');

// Weighted score: LI 45% + IG 35% + YT 20%
const liEng = liImpressions > 0 ? (liLikes + liComments*3 + liShares*5) / liImpressions * 100 : 0;
const igEng = igReach > 0 ? (igLikes + igComments*3 + igSaves*4) / igReach * 100 : 0;
const ytEng = ytViews > 0 ? (ytLikes + ytComments*3) / ytViews * 100 : 0;
const score = Math.min(100, Math.round((liEng*45 + igEng*35 + ytEng*20) * 10) / 10);
const label = score >= 7 ? 'HIGH' : score >= 3 ? 'MEDIUM' : 'LOW';

console.log(`Score: ${score}/100 | LI:${liLikes} IG:${igLikes} YT:${ytViews}views`);

return [{
  json: {
    post_id: scheduled.post_id,
    li_likes: liLikes, li_comments: liComments, li_shares: liShares, li_impressions: liImpressions,
    ig_likes: igLikes, ig_comments: igComments, ig_reach: igReach, ig_saves: igSaves,
    yt_views: ytViews, yt_likes: ytLikes, yt_comments: ytComments,
    performance_score: score, performance_label: label,
    score_notes: `LI:${liEng.toFixed(1)}% IG:${igEng.toFixed(1)}% YT:${ytEng.toFixed(1)}% → ${score}/100`,
    analyzed_at: new Date().toISOString()
  }
}];

